errorLoggingMiddleware = (): MiddlewareHandler => {
	return async (c: Context, next) => {
		try {
			await next();
		} catch (error) {
			const correlationId = c.get("correlationId") || "unknown";
			const user = c.get("user");

			// Log the error with full context
			systemLogger.error(
				{
					correlationId,
					method: c.req.method,
					path: c.req.path,
					user: user
						? {
								id: user.id,
								email: user.email,
								role: user.role,
							}
						: null,
					userAgent: c.req.header("user-agent"),
					ip: c.req.header("x-forwarded-for") || c.req.header("x-real-ip"),
					err: {
						name: error instanceof Error ? error.name : "Unknown",
						message: error instanceof Error ? error.message : String(error),
						stack: error instanceof Error ? error.stack : undefined,
					},
					timestamp: new Date().toISOString(),
				},
				`Unhandled error in ${c.req.method} ${c.req.path}`,
			);

			// Re-throw to let Hono handle the error response
			throw error;
		}
	};
}

export async function executeRequest(
  app: Hono,
  requestPath: string,
  options: RequestOptions
): Promise<{ status: number; body: string; headers: Record<string, string>; response: Response }> {
  // Build request
  const url = new URL(requestPath, 'http://localhost')
  const requestInit: RequestInit = {
    method: options.method || 'GET',
  }

  // Add request body if provided
  if (options.data) {
    requestInit.body = options.data
  }

  // Add headers if provided
  if (options.header && options.header.length > 0) {
    const headers = new Headers()
    for (const header of options.header) {
      const [key, value] = header.split(':', 2)
      if (key && value) {
        headers.set(key.trim(), value.trim())
      }
    }
    requestInit.headers = headers
  }

  // Execute request
  const request = new Request(url.href, requestInit)
  const response = await app.request(request)

  // Convert response to our format
  const responseHeaders: Record<string, string> = {}
  response.headers.forEach((value, key) => {
    responseHeaders[key] = value
  })

  const body = await response.clone().text()

  return {
    status: response.status,
    body,
    headers: responseHeaders,
    response: response,
  }
}

publicCache = (entityType: ProductEntityType, idParam = 'id'): MiddlewareHandler<Env> =>
  xMiddleware(
    {
      functionName: 'publicCache',
      type: 'x-cache',
      name: 'public',
      description: `LRU cache for public ${entityType} entities`,
    },
    async (ctx, next) => {
      // Extract entity ID from route params
      const entityId = ctx.req.param(idParam);

      if (!entityId) {
        ctx.set('entityCacheHit', false);
        await next();
        return;
      }

      // Check LRU cache
      const cached = publicEntityCache.get(entityType, entityId);

      if (cached) {
        ctx.set('entityCacheHit', true);
        ctx.header('X-Cache', 'HIT');
        return ctx.json(cached);
      }

      // Cache miss - proceed to handler for fetch/enrichment
      ctx.set('entityCacheHit', false);

      await next();

      // After handler: cache the response if data was set
      const entityData = ctx.get('entityCacheData');

      if (entityData) {
        publicEntityCache.set(entityType, entityId, entityData);
        ctx.header('X-Cache', 'MISS');
      }
    },
  )

function createQRRedirectHandler(): Hono {
  const app = new Hono()

  app.get('/qr/:code', async (c: Context) => {
    const code = c.req.param('code')
    // Get database from context - SonicJS provides db via c.get('db') or c.env.DB
    const db: D1Database = (c.get('db') || (c.env as any)?.DB) as D1Database

    if (!db) {
      console.error('[QR Redirect] Database not available')
      return c.notFound()
    }

    // Query redirect by source path
    // The redirect was created by QR generator with source = /qr/{code}
    const redirect = await db
      .prepare(`
        SELECT destination, deleted_at, is_active
        FROM redirects
        WHERE source = ?
        LIMIT 1
      `)
      .bind(`/qr/${code}`)
      .first()

    // No redirect exists - 404
    if (!redirect) {
      return c.notFound()
    }

    // Soft-deleted or inactive - show expired page with 410 Gone
    if (redirect.deleted_at || redirect.is_active === 0) {
      return c.html(expiredQRPage(), 410)
    }

    // Active redirect - 302 to destination
    // Using 302 (temporary) allows destination changes without cache issues
    return c.redirect(redirect.destination as string, 302)
  })

  return app
}

#newResponse(
  data: Data | null,
  arg?: StatusCode | ResponseOrInit,
  headers?: HeaderRecord
): Response {
  const responseHeaders = this.#res
    ? new Headers(this.#res.headers)
    : (this.#preparedHeaders ?? new Headers())

  if (typeof arg === 'object' && 'headers' in arg) {
    const argHeaders = arg.headers instanceof Headers ? arg.headers : new Headers(arg.headers)
    for (const [key, value] of argHeaders) {
      if (key.toLowerCase() === 'set-cookie') {
        responseHeaders.append(key, value)
      } else {
        responseHeaders.set(key, value)
      }
    }
  }

  if (headers) {
    for (const [k, v] of Object.entries(headers)) {
      if (typeof v === 'string') {
        responseHeaders.set(k, v)
      } else {
        responseHeaders.delete(k)
        for (const v2 of v) {
          responseHeaders.append(k, v2)
        }
      }
    }
  }

  const status = typeof arg === 'number' ? arg : (arg?.status ?? this.#status)
  return createResponseInstance(data, { status, headers: responseHeaders })
}

export const cloneRawRequest = async (req: HonoRequest): Promise<Request> => {
  if (!req.raw.bodyUsed) {
    return req.raw.clone()
  }

  const cacheKey = (Object.keys(req.bodyCache) as Array<keyof Body>)[0]
  if (!cacheKey) {
    throw new HTTPException(500, {
      message:
        'Cannot clone request: body was already consumed and not cached. Please use HonoRequest methods (e.g., req.json(), req.text()) instead of consuming req.raw directly.',
    })
  }

  const requestInit: RequiredRequestInit = {
    body: await req[cacheKey](),
    cache: req.raw.cache,
    credentials: req.raw.credentials,
    headers: req.header(),
    integrity: req.raw.integrity,
    keepalive: req.raw.keepalive,
    method: req.method,
    mode: req.raw.mode,
    redirect: req.raw.redirect,
    referrer: req.raw.referrer,
    referrerPolicy: req.raw.referrerPolicy,
    signal: req.raw.signal,
  }

  return new Request(req.url, requestInit)
}

function adminSetupMiddleware() {
  return async (c: Context, next: Next) => {
    const path = new URL(c.req.url).pathname

    // Skip auth routes - always allow access
    if (path.startsWith('/auth/')) {
      return next()
    }

    // Skip static assets
    if (path.match(/\.(js|css|ico|png|jpg|jpeg|gif|svg|woff|woff2|ttf|eot)$/)) {
      return next()
    }

    // Skip health check endpoint
    if (path === '/health') {
      return next()
    }

    // Skip API routes that might be needed during setup
    if (path.startsWith('/api/')) {
      return next()
    }

    // Check if admin exists (uses in-memory cache after first check)
    const db = c.env.DB
    const adminExists = await checkAdminUserExists(db)

    if (!adminExists) {
      // Only redirect admin routes when no admin exists
      // Let other routes proceed normally (including 404s)
      if (path.startsWith('/admin')) {
        return c.redirect('/auth/register?setup=true')
      }
    }

    return next()
  }
}

function requireSubscription() {
  return async (c: Context<{ Bindings: Bindings; Variables: Variables }>, next: Next) => {
    const user = c.get('user')
    if (!user) {
      return c.json({ error: 'Authentication required' }, 401)
    }

    const db = c.env.DB
    const subscriptionService = new SubscriptionService(db)

    try {
      await subscriptionService.ensureTable()
      const subscription = await subscriptionService.getByUserId(user.userId)

      if (!subscription || (subscription.status !== 'active' && subscription.status !== 'trialing')) {
        return c.json({
          error: 'Active subscription required',
          subscription: subscription ? { status: subscription.status } : null
        }, 403)
      }

      // Proceed with the request
      return next()
    } catch (error) {
      console.error('[Stripe] Error checking subscription:', error)
      return c.json({ error: 'Subscription check failed' }, 500)
    }
  }
}

function addSSRCheck(funcName: string, componentName: string, componentExport?: string) {
  const isSSR = memberExpression(
    memberExpression(metaProperty(identifier('import'), identifier('meta')), identifier('env')),
    identifier('SSR')
  )

  const props = [
    jsxAttribute(jsxIdentifier('componentName'), stringLiteral(componentName)),
    jsxAttribute(jsxIdentifier('Component'), jsxExpressionContainer(identifier(funcName))),
    jsxAttribute(jsxIdentifier('props'), jsxExpressionContainer(identifier('props'))),
  ]
  if (componentExport && componentExport !== 'default') {
    props.push(jsxAttribute(jsxIdentifier('componentExport'), stringLiteral(componentExport)))
  }

  const ssrElement = jsxElement(
    jsxOpeningElement(jsxIdentifier('HonoXIsland'), props, true),
    null,
    []
  )

  const clientElement = jsxElement(
    jsxOpeningElement(jsxIdentifier(funcName), [jsxSpreadAttribute(identifier('props'))], false),
    jsxClosingElement(jsxIdentifier(funcName)),
    []
  )

  const returnStmt = returnStatement(conditionalExpression(isSSR, ssrElement, clientElement))
  return functionExpression(null, [identifier('props')], blockStatement([returnStmt]))
}

function respondWithOpenApiDocument(
  c: Context,
  input?: string | Record<string, any>,
  format: 'json' | 'yaml' = 'json',
) {
  if (!input) {
    return c.text('Not found', 404)
  }

  try {
    const document = normalize(input)

    // JSON
    if (format === 'json') {
      return c.json(document)
    }

    // YAML
    try {
      const yamlDocument = toYaml(normalize(document))

      c.header('Content-Type', 'text/yaml')
      return c.text(yamlDocument, 200, {
        'Content-Type': 'application/yaml; charset=UTF-8',
      })
    } catch (error) {
      return c.json(
        {
          error: 'Failed to convert document to YAML',
          message: error instanceof Error ? error.message : 'Unknown error occurred',
        },
        500,
      )
    }
  } catch (error) {
    return c.json(
      {
        error: 'Failed to parse OpenAPI document',
        message: error instanceof Error ? error.message : 'Unknown error occurred',
      },
      400,
    )
  }
}

async function deleteComment(userId: string, id: string) {
  const [existing] = await db
    .select({
      id: activityTable.id,
      content: activityTable.content,
      taskId: activityTable.taskId,
    })
    .from(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .limit(1);

  if (!existing) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [deletedComment] = await db
    .delete(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .returning();

  if (!deletedComment) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, deletedComment.taskId))
    .limit(1);

  if (task) {
    await publishEvent("comment.deleted", {
      ...deletedComment,
      projectId: task.projectId,
      userId,
    });
  }

  deleteOrphanedAssets(existing.content, null, {
    taskId: existing.taskId,
  }).catch(() => {});

  return deletedComment;
}

async function updateComment(userId: string, id: string, content: string) {
  const [existing] = await db
    .select({
      id: activityTable.id,
      content: activityTable.content,
      taskId: activityTable.taskId,
    })
    .from(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .limit(1);

  if (!existing) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [updated] = await db
    .update(activityTable)
    .set({ content })
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .returning();

  if (!updated) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, updated.taskId))
    .limit(1);

  if (task) {
    await publishEvent("comment.updated", {
      ...updated,
      projectId: task.projectId,
      userId,
    });
  }

  deleteOrphanedAssets(existing.content, content, {
    taskId: existing.taskId,
  }).catch(() => {});

  return updated;
}

async function updateTaskDescription({
  id,
  description,
  currentUserId,
}: {
  id: string;
  description: string;
  currentUserId: string;
}) {
  const existingTask = await db.query.taskTable.findFirst({
    where: eq(taskTable.id, id),
  });

  if (!existingTask) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  const [updatedTask] = await db
    .update(taskTable)
    .set({ description })
    .where(eq(taskTable.id, id))
    .returning();

  if (!updatedTask) {
    throw new HTTPException(500, {
      message: "Failed to update task description",
    });
  }

  await publishEvent("task.description_changed", {
    taskId: updatedTask.id,
    projectId: updatedTask.projectId,
    userId: currentUserId,
    oldDescription: existingTask.description,
    newDescription: description,
    type: "description_changed",
  });

  deleteOrphanedAssets(existingTask.description, description, {
    taskId: id,
  }).catch(() => {});

  return updatedTask;
}

async function updateTaskDueDate({
  id,
  dueDate,
  currentUserId,
}: {
  id: string;
  dueDate: Date | null;
  currentUserId: string;
}) {
  const existingTask = await db.query.taskTable.findFirst({
    where: eq(taskTable.id, id),
  });

  if (!existingTask) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  // Clear sent reminders so new due date triggers fresh notifications
  await db
    .delete(taskReminderSentTable)
    .where(eq(taskReminderSentTable.taskId, id));

  const [updatedTask] = await db
    .update(taskTable)
    .set({ dueDate: dueDate || null })
    .where(eq(taskTable.id, id))
    .returning();

  if (!updatedTask) {
    throw new HTTPException(500, {
      message: "Failed to update task due date",
    });
  }

  await publishEvent("task.due_date_changed", {
    taskId: updatedTask.id,
    projectId: updatedTask.projectId,
    userId: currentUserId,
    oldDueDate: existingTask.dueDate,
    newDueDate: dueDate,
    title: updatedTask.title,
    type: "due_date_changed",
  });

  return updatedTask;
}

async function validateCsrfToken(token: string, secret: string): Promise<boolean> {
  if (!token || typeof token !== 'string') return false

  const dotIndex = token.indexOf('.')
  if (dotIndex === -1) return false

  const nonce = token.substring(0, dotIndex)
  const signature = token.substring(dotIndex + 1)

  if (!nonce || !signature) return false

  try {
    const key = await getHmacKey(secret)
    const encoder = new TextEncoder()

    // Decode the signature from base64url
    const sigPadded = signature.replace(/-/g, '+').replace(/_/g, '/')
    const sigBinary = atob(sigPadded)
    const sigBytes = new Uint8Array(sigBinary.length)
    for (let i = 0; i < sigBinary.length; i++) {
      sigBytes[i] = sigBinary.charCodeAt(i)
    }

    // crypto.subtle.verify is constant-time
    return await crypto.subtle.verify('HMAC', key, sigBytes.buffer, encoder.encode(nonce))
  } catch {
    return false
  }
}

async function getProjects(workspaceId: string, includeArchived = false) {
  const projects = await db.query.projectTable.findMany({
    where: includeArchived
      ? eq(projectTable.workspaceId, workspaceId)
      : and(
          eq(projectTable.workspaceId, workspaceId),
          isNull(projectTable.archivedAt),
        ),
    with: {
      tasks: true,
    },
  });

  const projectsWithStatistics = projects.map((project) => {
    const totalTasks = project.tasks.length;
    const completedTasks = project.tasks.filter(
      (task) => task.status === "done" || task.status === "archived",
    ).length;
    const completionPercentage =
      totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

    const dueDate = project.tasks.reduce((earliest: Date | null, task) => {
      if (!earliest || (task.dueDate && task.dueDate < earliest))
        return task.dueDate;
      return earliest;
    }, null);

    return {
      ...project,
      statistics: {
        completionPercentage,
        totalTasks,
        dueDate,
      },
      archivedTasks: [],
      plannedTasks: [],
      columns: [],
    };
  });

  return projectsWithStatistics;
}

export function getBuildIterator(
  appPath: string | undefined,
  watch: boolean,
  external: string[] = []
): AsyncGenerator<Hono> {
  // Determine entry file path
  let entry: string
  let resolvedAppPath: string

  if (appPath) {
    // If appPath is provided, use it as-is (could be relative or absolute)
    entry = appPath
    resolvedAppPath = resolve(process.cwd(), entry)
  } else {
    // Use default candidates
    entry =
      DEFAULT_ENTRY_CANDIDATES.find((candidate) => existsSync(resolve(process.cwd(), candidate))) ??
      DEFAULT_ENTRY_CANDIDATES[0]
    resolvedAppPath = resolve(process.cwd(), entry)
  }

  if (!existsSync(resolvedAppPath)) {
    throw new Error(`Entry file ${entry} does not exist`)
  }

  const appFilePath = realpathSync(resolvedAppPath)
  return buildAndImportApp(appFilePath, {
    external: ['@hono/node-server', ...external],
    watch,
    sourcemap: true,
  })
}

export const hydrateComponentHonoSuspense = async (hydrateComponent: HydrateComponent) => {
  const templates = new Set<Element>()
  const observerTargets = new Set<Element>()
  document.querySelectorAll('template[id^="H:"], template[id^="E:"]').forEach((template) => {
    if (template.parentElement) {
      templates.add(template)
      observerTargets.add(template.parentElement)
    }
  })

  if (observerTargets.size === 0) {
    return
  }

  const observer = new MutationObserver((mutations) => {
    const targets = new Set<Element>()
    mutations.forEach((mutation) => {
      if (mutation.target instanceof Element) {
        targets.add(mutation.target)
        mutation.removedNodes.forEach((node) => {
          templates.delete(node as Element)
        })
      }
    })
    targets.forEach((target) => {
      hydrateComponent(target)
    })

    if (templates.size === 0) {
      // all templates have been hydrated
      observer.disconnect()
    }
  })
  observerTargets.forEach((target) => {
    observer.observe(target, { childList: true })
  })
}

export const createStandardMetrics = ({
  registry,
  prefix = '',
  customOptions,
}: {
  registry: Registry
  prefix?: string
  customOptions?: CustomMetricsOptions
}) => {
  const createdMetrics: Record<string, Metric> = {}

  for (const [metric, options] of Object.entries(standardMetrics)) {
    const opts: MetricOptions = {
      ...options,
      ...customOptions?.[metric as MetricName],
    }

    if (opts.disabled) {
      continue
    }

    const MetricConstructor = getMetricConstructor(opts.type)

    createdMetrics[metric] = new MetricConstructor({
      ...(opts as object),
      name: `${prefix}${opts.name}`,
      help: opts.help,
      registers: [...(opts.registers ?? []), registry],
      labelNames: [...(opts.labelNames ?? []), ...Object.keys(opts.customLabels ?? {})],
      ...(opts.type === 'histogram' &&
        opts.buckets && {
          buckets: opts.buckets,
        }),
    })
  }

  return createdMetrics as CreatedMetrics
}

function getRateLimiter(
  operation: ApiRateLimitOperation,
  env: AppBindings['Bindings'],
): Ratelimit | null {
  const key = `${operation}-free`; // Using free tier for now

  const rateLimitEnabled = resolveApiRateLimitEnabled(env, true);
  if (!rateLimitEnabled) {
    return null;
  }

  const credentials = resolveUpstashRedisCredentials(env);
  if (!credentials) {
    warnMissingUpstashOnce();
    return null;
  }

  let ratelimit = rateLimiters.get(key);
  if (!ratelimit) {
    ratelimit = new Ratelimit({
      // Avoid Redis.fromEnv() warnings by validating credentials first.
      redis: Redis.fromEnv(env),
      limiter: Ratelimit.slidingWindow(
        API_RATE_LIMIT_RULES[operation].free.limit,
        API_RATE_LIMIT_RULES[operation].free.window as Duration,
      ),
      ephemeralCache: EPHEMERAL_CACHE,
      analytics: true,
      prefix: `ratelimit:${operation}`,
    });
    rateLimiters.set(key, ratelimit);
  }

  return ratelimit;
}

async function getGiteaIntegration(projectId: string) {
  const integration = await db.query.integrationTable.findFirst({
    where: and(
      eq(integrationTable.projectId, projectId),
      eq(integrationTable.type, "gitea"),
    ),
  });

  if (!integration) {
    return null;
  }

  const config = JSON.parse(integration.config) as GiteaConfig;

  const apiBase = normalizeApiServerUrl(
    process.env.KANEO_API_URL || "http://localhost:1337",
  );

  return {
    id: integration.id,
    projectId: integration.projectId,
    baseUrl: config.baseUrl,
    repositoryOwner: config.repositoryOwner,
    repositoryName: config.repositoryName,
    maskedAccessToken: maskToken(config.accessToken),
    webhookUrl: `${apiBase.replace(/\/$/, "")}/gitea-integration/webhook/${integration.id}`,
    webhookSecret: config.webhookSecret ?? "",
    branchPattern: config.branchPattern || defaultGiteaConfig.branchPattern,
    commentTaskLinkOnGiteaIssue: config.commentTaskLinkOnGiteaIssue !== false,
    isActive: integration.isActive,
    createdAt: integration.createdAt,
    updatedAt: integration.updatedAt,
  };
}

async function listGiteaRepositories({
  baseUrl,
  accessToken,
}: {
  baseUrl: string;
  accessToken: string;
}): Promise<{ repositories: RepoRow[] }> {
  const normalized = normalizeGiteaBaseUrl(baseUrl);

  try {
    await verifyGiteaToken(normalized, accessToken);
  } catch {
    throw new HTTPException(401, {
      message: "Invalid Gitea token or could not reach instance.",
    });
  }

  const client = createGiteaClient({
    baseUrl: normalized,
    accessToken,
  });

  const all: RepoRow[] = [];
  let page = 1;

  while (true) {
    const batch = await client.listUserRepos(page, 50);
    if (!batch.length) break;

    for (const repo of batch) {
      const ownerLogin = repo.owner?.login ?? repo.owner?.username ?? "";
      all.push({
        id: repo.id,
        name: repo.name,
        full_name: repo.full_name,
        private: repo.private,
        owner: { login: ownerLogin },
        html_url: repo.html_url,
      });
    }

    if (batch.length < 50) break;
    page += 1;
    if (page > 50) break;
  }

  return { repositories: all };
}

async function createNotification({
  userId,
  title,
  content,
  type,
  eventData,
  resourceId,
  resourceType,
}: {
  userId: string;
  title?: string | null;
  content?: string | null;
  type?: string;
  eventData?: Record<string, unknown> | null;
  resourceId?: string;
  resourceType?: string;
}) {
  const [notification] = await db
    .insert(notificationTable)
    .values({
      id: createId(),
      userId,
      title: title ?? null,
      content: content ?? null,
      type: type || "info",
      eventData: eventData ?? null,
      resourceId: resourceId || null,
      resourceType: resourceType || null,
    })
    .returning();

  if (notification) {
    await publishEvent("notification.created", {
      notificationId: notification.id,
      userId,
    });
    void deliverNotification(notification.id).catch((error) => {
      console.error("Failed to deliver notification", {
        notificationId: notification.id,
        error,
      });
    });
  }

  return notification;
}

async function deleteTaskRelation(id: string, userId: string) {
  const [rel] = await db
    .select({
      sourceTaskId: taskRelationTable.sourceTaskId,
      targetTaskId: taskRelationTable.targetTaskId,
    })
    .from(taskRelationTable)
    .where(eq(taskRelationTable.id, id))
    .limit(1);

  if (!rel) {
    throw new HTTPException(404, {
      message: "Task relation not found",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, rel.sourceTaskId))
    .limit(1);

  const [relation] = await db
    .delete(taskRelationTable)
    .where(eq(taskRelationTable.id, id))
    .returning();

  if (!relation) {
    throw new HTTPException(404, {
      message: "Task relation not found",
    });
  }

  if (task) {
    await publishEvent("task-relation.deleted", {
      ...relation,
      taskId: rel.sourceTaskId,
      sourceTaskId: rel.sourceTaskId,
      targetTaskId: rel.targetTaskId,
      projectId: task.projectId,
      userId,
    });
  }

  return relation;
}

async function resolveDestinationStatus(
  destinationProjectId: string,
  currentStatus: string,
  requestedStatus?: string,
) {
  const destinationColumns = await db
    .select({
      id: columnTable.id,
      slug: columnTable.slug,
      position: columnTable.position,
    })
    .from(columnTable)
    .where(eq(columnTable.projectId, destinationProjectId))
    .orderBy(asc(columnTable.position));

  if (destinationColumns.length === 0) {
    throw new HTTPException(400, {
      message: "Destination project does not have a workflow",
    });
  }

  const requestedColumn = requestedStatus
    ? destinationColumns.find((column) => column.slug === requestedStatus)
    : null;

  if (requestedStatus && !requestedColumn) {
    throw new HTTPException(400, {
      message: "Selected status is not valid for the destination project",
    });
  }

  const matchingCurrentColumn = destinationColumns.find(
    (column) => column.slug === currentStatus,
  );

  return requestedColumn ?? matchingCurrentColumn ?? destinationColumns[0];
}

async function updateTimeEntry(params: UpdateTimeEntryParams) {
  const { timeEntryId, startTime, endTime, description } = params;

  const [existingTimeEntry] = await db
    .select()
    .from(timeEntryTable)
    .where(eq(timeEntryTable.id, timeEntryId));

  if (!existingTimeEntry) {
    throw new HTTPException(404, {
      message: "Time entry not found",
    });
  }

  // Calculate duration if both startTime and endTime are provided
  let duration: number | null = null;
  if (endTime) {
    duration = Math.floor((endTime.getTime() - startTime.getTime()) / 1000); // duration in seconds
  }

  const [updatedTimeEntry] = await db
    .update(timeEntryTable)
    .set({
      startTime,
      endTime: endTime || null,
      duration,
      ...(description !== undefined && { description }),
    })
    .where(eq(timeEntryTable.id, timeEntryId))
    .returning();

  return updatedTimeEntry;
}

handleEmailVerification = async (ctx: Context<Env>, token: TokenModel) => {
  // Token requires userId
  if (!token.userId) throw new AppError(500, 'server_error', 'error');

  // Get user
  const [user] = await db.select(userSelect).from(usersTable).where(eq(usersTable.id, token.userId)).limit(1);
  if (!user) throw new AppError(404, 'not_found', 'error', { entityType: 'user', meta: { userId: token.userId } });

  // Set email verified if it exists
  await db
    .update(emailsTable)
    .set({ verified: true, verifiedAt: getIsoDate() })
    .where(
      and(
        eq(emailsTable.tokenId, token.id),
        eq(emailsTable.userId, token.userId),
        eq(emailsTable.email, token.email),
        eq(emailsTable.verified, false),
      ),
    );

  // Start MFA challenge if the user has MFA enabled
  const mfaRedirectPath = await initiateMfa(ctx, user);

  // Determine redirect path — new users go to welcome page
  const redirectPath = mfaRedirectPath || getPostAuthRedirectPath(user);
  const redirectUrl = new URL(redirectPath, appConfig.frontendUrl);

  // If MFA is not required, set user session immediately
  if (!mfaRedirectPath) await setUserSession(ctx, user, 'email');

  return ctx.redirect(redirectUrl, 302);
}

canonicalizeFilePath = (
  filePath: string,
  outputDir: string,
  baseUrl: string,
  canonicalize: boolean = true
): { routePath: string; url: string } => {
  const posixFilePath = filePath.replace(/\\/g, '/')
  const posixOutputDir = outputDir.replace(/\\/g, '/')
  const outputDirCanonical = path.posix.resolve(path.posix.normalize(posixOutputDir))
  const filePathResolved = path.posix.resolve(path.posix.normalize(posixFilePath))
  const relativePath = path.relative(outputDirCanonical, filePathResolved)

  let routePath = '/' + relativePath
  if (routePath.endsWith('/index.html')) {
    routePath = routePath.slice(0, -'index.html'.length) || '/'
  } else if (routePath.endsWith('.html')) {
    routePath = routePath.slice(0, -'.html'.length)
  }
  const canonicalBaseUrl = baseUrl.endsWith('/') ? baseUrl : `${baseUrl}/`
  let url: string
  if (relativePath.endsWith('index.html')) {
    const dir = relativePath.slice(0, -'index.html'.length)
    url = new URL(dir, canonicalBaseUrl).toString()
  } else if (canonicalize && relativePath.endsWith('.html')) {
    url = new URL(relativePath.slice(0, -'.html'.length), canonicalBaseUrl).toString()
  } else {
    url = new URL(relativePath, canonicalBaseUrl).toString()
  }
  return { routePath, url }
}

async parse(
  sitemapUrl: string,
  options?: { signal?: AbortSignal | null },
): Promise<{ urls: string[]; content: string | null }> {
  try {
    const response = await fetch(sitemapUrl, { signal: options?.signal });
    if (!response.ok) {
      return { urls: [], content: null };
    }

    const content = await response.text();
    const urls: string[] = [];

    // Extract URLs from both XML sitemaps and sitemap indexes
    const urlMatches = content.match(/<loc>([^<]+)<\/loc>/g);
    if (urlMatches) {
      for (const match of urlMatches) {
        const url = match.replace(/<\/?loc>/g, '');
        urls.push(url);
      }
    }

    // If this is a sitemap index, recursively fetch all sub-sitemaps
    if (content.includes('<sitemapindex')) {
      const subSitemapUrls = urls.slice();
      urls.length = 0;

      for (const subSitemapUrl of subSitemapUrls) {
        const subResult = await this.parse(subSitemapUrl, options);
        urls.push(...subResult.urls);
      }
    }

    return { urls, content };
  } catch (error) {
    return { urls: [], content: null };
  }
}

function resolveRedisMode(): RedisMode {
  const clusterNodes = process.env.REDIS_CLUSTER_NODES;
  if (clusterNodes) {
    return {
      mode: "cluster",
      nodes: parseNodeList(clusterNodes, "REDIS_CLUSTER_NODES", 6379),
      password: process.env.REDIS_PASSWORD,
    };
  }

  const sentinels = process.env.REDIS_SENTINELS;
  if (sentinels) {
    return {
      mode: "sentinel",
      sentinels: parseNodeList(sentinels, "REDIS_SENTINELS", 26379),
      name: process.env.REDIS_SENTINEL_MASTER_NAME || "mymaster",
      password: process.env.REDIS_PASSWORD,
      sentinelPassword: process.env.REDIS_SENTINEL_PASSWORD,
      enableTLSForSentinelMode: process.env.REDIS_SENTINEL_TLS === "true",
    };
  }

  const url = process.env.REDIS_URL;
  if (!url) {
    throw new Error(
      "REDIS_URL, REDIS_SENTINELS, or REDIS_CLUSTER_NODES must be set",
    );
  }
  return { mode: "standalone", url };
}
